class Geometry:
    @static
    PI: float = 3.14159

def area_of_circle(radius: float) -> float:
    return Geometry.PI * radius * radius

def area_of_rectangle(width: float, height: float) -> float:
    return width * height

def perimeter_of_circle(radius: float) -> float:
    return 2.0 * Geometry.PI * radius

